VALUES ('tsp-loop-588', 588, 'Inference application spine', 'CLOSED', 'tsp-rule-inference-application-spine', 'Inference application spine', 'Represented 5 applications, 5 antecedents, 5 selected edge states, and 10 supports; no edge was labeled FORCED.', 'Union supported edge selections into a derived structural edge set.', 'Represent local-bound applications, antecedents, selected edge states, and support rows without upgrading selected edges to forced edges.', 'Inference rules exist, but individual applications, antecedents, edge decisions, and supports are not first-class rows.', 'Represented 5 applications, 5 antecedents, 5 selected edge states, and 10 supports; no edge was labeled FORCED.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

