VALUES ('tsp-loop-590', 590, 'Connected degree-two certificate', 'CLOSED', 'tsp-rule-connected-degree-two-certificate', 'Connected degree-two certificate', 'All five stops have selected degree two; component count=1, spanning-tree edges=4, proper subtours=0.', 'Reconstruct an ordered cycle from the certified edge set.', 'Witness selected degree two at all five stops, one connected component, a four-edge spanning tree, and zero proper subtours.', 'The inferred Gridville edge union has no represented degree, component, spanning-tree, or subtour certificate.', 'All five stops have selected degree two; component count=1, spanning-tree edges=4, proper subtours=0.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

