VALUES ('tsp-loop-592', 592, 'Derived search accounting', 'CLOSED', 'tsp-rule-derived-search-accounting', 'Derived search accounting', 'Derived 12 initial route classes, one surviving reconstructed class, zero branch decisions, zero backtracks, and zero residual ambiguity.', 'Add a fixture where the degree-two lower bound is sound but non-tight.', 'Derive 12 initial symmetry-reduced classes, one surviving reconstructed class, zero branch decisions, zero backtracks, and zero residual ambiguity for Gridville.', 'Route-discovery counts are recorded as baseline data and are not tied to a structural reconstruction certificate.', 'Derived 12 initial route classes, one surviving reconstructed class, zero branch decisions, zero backtracks, and zero residual ambiguity.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

