VALUES ('tsp-loop-596', 596, 'Neighborhood boundary-state contraction v0', 'CLOSED', 'tsp-rule-neighborhood-boundary-state', 'Neighborhood boundary-state contraction v0', 'Each twin-triangle neighborhood contracts six raw internal orders to three undirected boundary states (50%); paired composition contracts 36 combinations to nine (75%) with cost-preserving path witnesses.', 'Generalize boundary-state soundness across non-triangular clusters and then branch only on residual city-level ambiguity.', 'For each three-stop twin-triangle neighborhood, derive three undirected entry/exit Hamiltonian-path states, reduce six internal orders to three states, and reduce 36 paired internal orders to nine paired boundary-state combinations.', 'Neighborhood rows are geographic labels only; no executable entry/exit path states or contraction certificate exists.', 'Each twin-triangle neighborhood contracts six raw internal orders to three undirected boundary states (50%); paired composition contracts 36 combinations to nine (75%) with cost-preserving path witnesses.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-597', 597, 'Convergence prediction', 'CLOSED', 'tsp-rule-predicate-invention', 'Convergence Prediction', 'The convergence hypothesis is now versioned data, explicitly exploratory and not a theorem.', 'Derive the explicit predicate basis and map the surface vocabulary onto it.', 'Record the working prediction, baseline thirty-two surface predicates, target eight-predicate basis, and DAG-based predicate-invention method without claiming a theorem.', 'Forty physical tables expose at least thirty-two recurring surface predicates, but no explicit convergence hypothesis or semantic compression baseline is recorded.', 'Recorded a thirty-two-surface-predicate baseline, an eight-predicate target, and the prediction that DAG inference will invent derived predicates while the primitive basis stabilizes.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-598', 598, 'Eight-predicate basis', 'CLOSED', 'tsp-rule-predicate-invention', 'Predicate Basis', 'Predicate basis = {MEMBERSHIP, INCIDENCE, CARDINALITY, ORDER, WEIGHT, COMMITMENT, CONNECTIVITY, PROVENANCE}; measured semantic compression is 75%.', 'Collapse edge-decision vocabulary into one ordered commitment concept.', 'Represent exactly eight canonical primitives and map all thirty-two baseline surface predicates to finite basis expressions.', 'The convergence prediction is recorded, but the candidate primitive vocabulary and surface-to-basis map do not exist.', 'Mapped thirty-two recurring surface predicates to eight canonical primitives; historical names remain queryable projections rather than independent primitives.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-599', 599, 'Edge commitment lattice', 'CLOSED', 'tsp-rule-predicate-invention', 'Commitment Lattice', 'Gridville selections have rank 1 and CURRENT_WITNESS scope; sparse forced edges have rank 2 and ALL_FEASIBLE_TOURS scope; no epistemic upgrade was hidden.', 'Collapse degree checks, local bounds, and forcing into one incidence budget.', 'Project all edge statuses onto one commitment rank, polarity, necessity scope, and provenance representation without conflating selected with forced.', 'UNKNOWN, SELECTED, FORCED, FORBIDDEN, CONTRADICTED, and SUPERSEDED are separate surface statuses split across edge-state and constraint-decision projections.', 'Collapsed edge-state and constraint-decision vocabulary into a commitment lattice with rank, polarity, necessity scope, and provenance.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-600', 600, 'Incidence budget', 'CLOSED', 'tsp-rule-predicate-invention', 'Incidence Budget', 'All five Gridville and all six twin-triangle stops have required incidence 2, observed incidence 2, and incidence defect 0; connectivity remains a separate coordinate.', 'Lift local incidence defects into a global multi-coordinate defect vector.', 'Represent required incidence, observed incidence, and incidence defect uniformly for every Gridville and twin-triangle stop.', 'Cycle degree, selected degree, remaining degree, local lower-bound incidence, and forcing applicability are represented as separate concepts.', 'Projected local degree bounds, cycle degree, selected degree, and forcing applicability onto one incidence budget.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-601', 601, 'Defect vector', 'CLOSED', 'tsp-rule-predicate-invention', 'Defect Vector', 'Gridville vector = 0|0|0|0; twin local two-factor vector = 0|1|2|18, locating the exact unresolved geometry without inventing a new primitive.', 'Derive the minimum crossing demand exposed by the twin component defect.', 'Represent incidence, connectivity, boundary, and cost defects as one vector and distinguish zero-defect Gridville from twin triangles.', 'Degree violations, connected-component count, boundary crossings, and cost gaps are separate acceptance surfaces.', 'Collapsed incidence violations, component excess, missing boundary crossings, and bound gap into one defect vector.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-602', 602, 'Cut parity', 'CLOSED', 'tsp-rule-cut-parity', 'Cut Parity', 'Twin component cut: crossing count is even for every cycle and nonzero for connected coverage; therefore crossing count >= 2.', 'Turn mandatory crossings into an additive component-repair lower bound.', 'Derive that a Hamiltonian cycle crosses a nontrivial component cut a positive even number of times, hence at least twice.', 'Twin triangles exposes two selected components, but the mandatory number of crossings between them is not represented.', 'Derived a positive-even cut-crossing certificate for the two twin components, with minimum crossing demand two.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-603', 603, 'Component repair bound', 'CLOSED', 'tsp-rule-component-repair-bound', 'Component Repair Bound', 'Twin component repair adjustment is +18; the strengthened finite-instance lower bound is 24.', 'Compare the repaired lower bound with the feasible candidate upper bound.', 'Add two cost-ten crossings, release two cost-one internal edges, and certify an eighteen-unit repair adjustment and lower bound twenty-four.', 'Twin triangles has a certified local degree bound of six and a two-crossing requirement, but no composed global repair cost.', 'Composed the local degree bound with cut repair: 6 + (2 x 10) - (2 x 1) = 24.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-604', 604, 'Bound sandwich', 'CLOSED', 'tsp-rule-bound-equality-optimality', 'Bound Sandwich', 'The original degree-only bound remains recorded as non-tight; the composed component-repair bound equals the valid candidate and proves optimality only for tsp-twin-triangles-6.', 'Normalize supplied and reconstructed routes into one witness shape.', 'Close twin-triangle finite optimality by lower-bound/upper-bound equality while retaining the original non-tight local-bound counterexample.', 'Twin triangles has a repaired lower bound of twenty-four and a feasible candidate of cost twenty-four, but no finite optimality certificate.', 'Closed twin-triangle optimality by the sandwich 24 <= candidate cost 24 <= 24.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-605', 605, 'Witness normal form', 'CLOSED', 'tsp-rule-witness-normal-form', 'Witness Normal Form', 'The supplied and reconstructed Gridville cycles share coverage, edge count, cost, and zero-defect semantic key; only provenance differs.', 'Extend the same normal form to neighborhood entry/exit paths.', 'Project supplied and reconstructed cycles into one normal form whose semantic key differs only by provenance where the underlying cycle is identical.', 'Candidate tours, reconstructed tours, and cluster paths use separate object vocabularies despite sharing coverage, incidence, order, connectivity, cost, and provenance.', 'Normalized supplied and reconstructed cycles into one semantic witness shape.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-606', 606, 'Boundary signature', 'CLOSED', 'tsp-rule-witness-normal-form', 'Boundary Signature', 'Each path normal form records scope, canonical entry/exit, three-stop coverage, two edges, cost two, zero defects, and expansion provenance.', 'Quotient boundary witnesses by semantic equivalence rather than raw orientation.', 'Project all six cluster boundary states into valid path normal forms keyed by scope, entry, exit, coverage, and cost.', 'Neighborhood boundary states are special-purpose rows rather than path witnesses in the common normal form.', 'Projected all six neighborhood boundary states into valid path witness normal forms.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-607', 607, 'Semantic quotient', 'CLOSED', 'tsp-rule-semantic-quotient', 'Semantic Quotient', 'Each neighborhood has six directed orders / orientation multiplicity two = three quotient classes; the product quotient has 3 x 3 = 9 classes.', 'Collapse neighborhoods and disconnected components into one boundary object.', 'Represent reversal-equivalent internal orders as quotient classes and derive three classes per neighborhood and nine product classes.', 'The measured six-to-three neighborhood contraction is stored as a count reduction without an explicit equivalence relation.', 'Recast neighborhood contraction as a semantic quotient by path reversal with fixed unordered boundary, coverage, and cost.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-608', 608, 'Component quotient', 'CLOSED', 'tsp-rule-semantic-quotient', 'Component Quotient', 'The city-level object is now a two-node quotient graph; cluster versus component is provenance, while boundary degree and expansion signature carry the semantics.', 'Collapse applications, rounds, supports, antecedents, and decisions into closure events.', 'Represent the two twin neighborhoods as quotient nodes with boundary degree two, unifying cluster and component interfaces.', 'Neighborhood clusters and selected connected components are treated as different kinds of objects despite exposing the same boundary-degree contract.', 'Unified the two neighborhoods and the two selected connected components as quotient nodes with required boundary degree two.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-609', 609, 'Closure event', 'CLOSED', 'tsp-rule-closure-event', 'Closure Event', '14 closure events cover selection, union, rigidity, reconstruction, forcing, forbidding, cut parity, repair, optimality, and quotienting.', 'Measure whether new derived vocabulary has stopped increasing the primitive basis.', 'Project representative selection, union, rigidity, reconstruction, forcing, forbidding, cut, repair, optimality, and quotient steps into one closure-event schema.', 'Inference applications, antecedents, supports, states, constraint rounds, and decisions are separate execution concepts.', 'Collapsed applications, states, antecedents, supports, rounds, and decisions into a common closure-event projection.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-610', 610, 'Convergence event', 'CLOSED', 'tsp-rule-predicate-invention', 'Convergence Event', 'Convergence event: semantic compression 75%, physical tables 40 to 45, coined terms 14, new primitives after basis discovery 0; status is early empirical support for this finite TSP domain.', 'Stress the eight-predicate basis on larger clusters and branch only after closure leaves a witnessed residual kernel.', 'Certify thirty-two-to-eight semantic compression, fourteen coined terms, zero new primitives after the basis loop, bounded physical schema growth, and an explicit residual kernel.', 'Thirteen reduction loops have coined derived predicates, but their cumulative compression and primitive-basis stability are not certified.', 'Certified a stable eight-predicate basis across fourteen reduction loops: thirty-two baseline surface predicates compress to eight primitives, fourteen useful terms were coined, and no new primitive appeared after loop 598.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-611', 611, 'Predicate/operator split', 'CLOSED', 'tsp-rule-atom-operator-refinement', 'Predicate–Operator Split', 'All eight loop-610 primitives retain their historical identity and receive explicit semantic-category and reduced-expression fields; current primitive count remains eight. The convergence objective is coherence rather than monotone row, table, or predicate-count reduction.', 'Test whether membership and incidence share one typed attachment atom.', 'Classify the eight historical predicates as candidate atoms or operator-derived concepts, preserve their loop-610 provenance, and record that local expansion is permitted when an opaque dependency is replaced by explicit reusable machinery. Measure convergence by coherence, reuse, trust-boundary reduction, and residual ambiguity rather than by monotone physical size.', 'Loop 610 records eight canonical predicates, but relational atoms and reusable operators are not distinguished. Convergence could also be misread as requiring monotone table or predicate shrinkage.', 'Separated the historical eight-predicate basis into candidate relational atoms and operator-derived concepts without changing the active basis. Recorded that local representational growth is compatible with global semantic convergence when it replaces opacity with reusable structure.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-612', 612, 'Attachment atom', 'CLOSED', 'tsp-rule-atom-operator-refinement', 'Attachment Atom', 'Every historical membership/incidence surface retains a reduced expression, while the active primitive count becomes seven.', 'Test whether cardinality, order, and weight share one valuation atom.', 'Introduce ATTACHMENT(subject, object, role), reduce MEMBERSHIP and INCIDENCE to typed attachment roles, and preserve every historical surface definition.', 'Membership and incidence are separate primitives even though both attach one object to a typed scope or endpoint.', 'Collapsed membership and incidence into ATTACHMENT with typed roles such as member, endpoint, entry, exit, and uses.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-613', 613, 'Valuation atom', 'CLOSED', 'tsp-rule-atom-operator-refinement', 'Valuation Atom', 'Degree is a valuation under incident-count, sequence is a valuation under ordinal-position, and cost is a valuation under the objective measure; active primitive count becomes five.', 'Test whether commitment and provenance share one warrant atom.', 'Introduce VALUATION(subject, measure, value), reduce count, ordinal, and cost predicates to valuation forms, and retain aggregation as an explicit pending operator.', 'Cardinality, order, and weight remain separate primitives despite all assigning values under a named measure.', 'Collapsed cardinality, order, and weight into VALUATION under explicit measures.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-614', 614, 'Warrant atom', 'CLOSED', 'tsp-rule-atom-operator-refinement', 'Warrant Atom', 'SELECTED remains a current-witness warrant, FORCED remains an all-feasible-tours warrant, and historical provenance remains queryable; active primitive count becomes four.', 'Move connectivity from the atom basis into a closure operator.', 'Introduce WARRANT(conclusion, source, modality), reduce commitment and provenance to warrant projections, and preserve necessity scope distinctions.', 'Commitment and provenance are separate primitives even though every commitment is a scoped conclusion warranted by sources and rules.', 'Collapsed commitment and provenance into WARRANT with explicit source, modality, and scope.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-615', 615, 'Closure operator', 'CLOSED', 'tsp-rule-operator-lift', 'Closure Operator', 'The current active atom count is three: ATTACHMENT, VALUATION, WARRANT. Connectedness, components, cuts, and reachability are closure results.', 'Lift count, sum, minimum, and parity into one aggregation operator.', 'Register CLOSURE as an operator over attachment relations, reduce CONNECTIVITY to closure, and leave exactly three active relational atoms.', 'Connectivity is still treated as a primitive rather than reachability closure over typed attachments.', 'Lifted connectivity from the primitive basis into CLOSURE over typed attachments.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-616', 616, 'Aggregate operator', 'CLOSED', 'tsp-rule-operator-lift', 'Aggregate Operator', 'Degree, edge count, lower-bound sum, fiber minimum, and convergence measurement now differ by measure and reducer, not by primitive type.', 'Lift symmetry and dominance contraction into one quotient operator.', 'Register AGGREGATE as the common count/sum/min/max/parity operator over attachments and valuations, with no new atom.', 'Counts, sums, minima, degrees, and repair totals are expressed through many surface formulas without one operator identity.', 'Lifted count, sum, minimum, maximum, parity, and signed repair arithmetic into AGGREGATE.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-617', 617, 'Quotient operator', 'CLOSED', 'tsp-rule-operator-lift', 'Quotient Operator', 'Path reversal, component abstraction, and later valuation dominance now share one operator contract.', 'Lift repeated closure rounds into one fixed-point operator.', 'Register QUOTIENT as the operator that identifies witnesses under an explicit equivalence relation and retains representatives plus expansion provenance.', 'Semantic Quotient and Component Quotient are coined predicates but quotienting is not represented as a reusable operator.', 'Lifted semantic and component contraction into QUOTIENT with explicit equivalence, representatives, and expansion warrant.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-618', 618, 'Fixed-point operator', 'CLOSED', 'tsp-rule-operator-lift', 'Fixed-Point Operator', 'Forcing, forbidding, repair, and quotient events can now be described as warranted transformations iterated until state stability.', 'Certify the current three-atom/four-operator factorization.', 'Register FIXPOINT as repeated warranted closure until no commitment changes, and map inference rounds and closure events onto it.', 'Closure events and constraint rounds expose repeated application, but fixed-point iteration is not explicit in the semantic basis.', 'Lifted repeated constraint and inference closure into FIXPOINT.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-619', 619, 'Three-atom basis', 'CLOSED', 'tsp-rule-atom-operator-refinement', 'Three-Atom Basis', 'Atoms = ATTACHMENT, VALUATION, WARRANT. Operators = CLOSURE, AGGREGATE, QUOTIENT, FIXPOINT. Thirty-two baseline surfaces compress to three active atoms (90.63%) for the represented domain.', 'Stress the reduced basis on a general boundary-port interface.', 'Certify ATTACHMENT, VALUATION, and WARRANT as the current atoms; CLOSURE, AGGREGATE, QUOTIENT, and FIXPOINT as operators; and express every registered concept without the old eight primitive tokens.', 'Three active atoms and four operators have emerged incrementally, but their coverage of the historical vocabulary is not certified.', 'Certified a current basis of three atoms and four operators while preserving the historical eight-predicate certificate.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-620', 620, 'Boundary port', 'CLOSED', 'tsp-rule-boundary-fiber', 'Boundary Port', 'All six existing triangle path states expose one entry, one exit, full internal coverage, orientation multiplicity two, and a canonical boundary-fiber key.', 'Build a non-symmetric four-stop neighborhood and group its path witnesses by boundary fiber.', 'Represent every existing cluster path through typed entry/exit ports, a common port contract, orientation multiplicity, and a boundary-fiber key.', 'Entry and exit stops remain special cluster fields rather than typed attachments with a reusable port contract.', 'Normalized existing cluster entries and exits as typed boundary ports over ATTACHMENT, VALUATION, and WARRANT.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

INSERT INTO tsp_loops (tsp_loop_id, loop_order, display_name, status, primary_inference_rule, new_concept, witness_summary, next_frontier, planned_closure_criterion, before_state, after_state, completion_disposition)
VALUES ('tsp-loop-621', 621, 'Boundary fiber', 'CLOSED', 'tsp-rule-boundary-fiber', 'Boundary Fiber', 'The twelve path rows retain twenty-four raw directed orientations, full four-stop coverage, explicit three-edge expansions, and unequal costs within every boundary fiber.', 'Collapse each boundary fiber by valuation dominance.', 'Represent an asymmetric four-stop complete neighborhood with twelve reversal-quotient path states grouped into six boundary fibers, retaining twenty-four directed orientations and explicit expansion members.', 'The three-stop fixture has one path per unordered boundary, so it cannot distinguish quotienting by symmetry from competing internal valuations.', 'Represented an asymmetric four-stop complete cluster as six boundary fibers containing twelve reversal-quotient path witnesses.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

