VALUES ('convergence-loop-598', 'tsp-loop-598', 'SEMANTIC_REDUCTION', 32, 8, 8, 32, 42, 'Predicate Basis', 'EARLY_SUPPORT', 'All thirty-two baseline surface predicates have explicit definitions over MEMBERSHIP, INCIDENCE, CARDINALITY, ORDER, WEIGHT, COMMITMENT, CONNECTIVITY, and PROVENANCE.', NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (tsp_convergence_measurement_id) DO UPDATE SET tsp_loop = EXCLUDED.tsp_loop, measurement_kind = EXCLUDED.measurement_kind, surface_concept_count_before = EXCLUDED.surface_concept_count_before, primitive_count_after = EXCLUDED.primitive_count_after, new_primitive_count = EXCLUDED.new_primitive_count, derived_alias_count = EXCLUDED.derived_alias_count, physical_table_count = EXCLUDED.physical_table_count, novel_term = EXCLUDED.novel_term, prediction_status = EXCLUDED.prediction_status, notes = EXCLUDED.notes, active_atom_count = EXCLUDED.active_atom_count, active_operator_count = EXCLUDED.active_operator_count, physical_table_delta_from_loop610 = EXCLUDED.physical_table_delta_from_loop610, open_frontier_count = EXCLUDED.open_frontier_count, named_concept_count = EXCLUDED.named_concept_count, allows_local_expansion = EXCLUDED.allows_local_expansion, coherence_direction = EXCLUDED.coherence_direction;

